  // 已有 trace：追加新 span
  const state = traceTracker.get(currentTraceId);
  if (state) {
    state.turnCount++;
    state.lastActivityAt = Date.now();
    state.recordedRoles.add(role);
  } else {
    // 可能从之前的进程恢复
    traceTracker.set(currentTraceId, {
      createdAt: Date.now(),
